// Chunk the extracted PDF text into overlapping segments
// 500-word chunks with 50-word overlap
const text = $input.first().json.text || $input.first().json.content || '';

if (!text || text.trim().length === 0) {
  throw new Error('No text extracted from PDF. Check the extraction step.');
}

const CHUNK_SIZE = 500;  // words per chunk
const OVERLAP = 50;      // words of overlap between chunks

const words = text.split(/\s+/).filter(w => w.length > 0);
const chunks = [];
let i = 0;

while (i < words.length) {
  const chunk = words.slice(i, i + CHUNK_SIZE).join(' ');
  if (chunk.trim().length > 30) { // skip very short fragments
    chunks.push({
      json: {
        pageContent: chunk,
        metadata: {
          source: 'relaypay-kb-v1',
          chunkIndex: chunks.length,
          startWord: i,
          endWord: Math.min(i + CHUNK_SIZE, words.length)
        }
      }
    });
  }
  i += (CHUNK_SIZE - OVERLAP);
}

console.log(`Created ${chunks.length} chunks from ${words.length} words`);
return chunks;
